10	export type ItemType = keyof typeof BASE_PREMIUM;
11	
12	export type Item = { type: ItemType; cursed?: boolean; enchantment?: number };
13	
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
17	const LOYALTY_YEARS_THRESHOLD = 2;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const CURSED_SURCHARGE_RATE = 0.5;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	
25	function itemSurcharge(item: Item): number {
26	  const base = BASE_PREMIUM[item.type];
27	  let surcharge = 0;
28	  if (item.cursed) {
29	    surcharge += base * CURSED_SURCHARGE_RATE;
30	  }
31	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
32	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
33	  }
34	  return surcharge;
35	}
36	
37	export function calculatePremium(items: Item[], customer?: { yearsWithMHPCO: number }, options?: { isFollowUp?: boolean }): number {
38	  const groups = new Map<ItemType, number>();
39	  let totalSurcharge = 0;
40	  for (const item of items) {
41	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
42	    totalSurcharge += itemSurcharge(item);
43	  }
44	
45	  let total = 0;
46	  for (const [type, count] of groups) {
47	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
48	      total += BLOCK_PREMIUM;
49	    } else {
50	      total += count * BASE_PREMIUM[type];
51	    }
52	  }
53	  let policyPremium = total + totalSurcharge;
54	  if (customer && customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
55	    policyPremium *= 1 - LOYALTY_DISCOUNT_RATE;
56	  }
57	  policyPremium += policyPremium * FIRST_INSURANCE_SURCHARGE_RATE;
58	  if (options?.isFollowUp) {
59	    policyPremium *= 1 - FOLLOW_UP_DISCOUNT_RATE;
60	  }
61	  return policyPremium;
62	}
